import React, { useEffect, useState } from 'react';
import ProductForm from './ProductForm';

export default function AdminProducts() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(false);
  const [editing, setEditing] = useState(null);
  const [msg, setMsg] = useState(null);

  function getToken() { return localStorage.getItem('token'); }

  async function load() {
    setLoading(true);
    try {
      const res = await fetch('http://localhost:5000/api/products');
      const data = await res.json();
      setProducts(data);
    } catch (err) {
      setMsg({ type: 'error', text: 'Could not load products' });
    } finally { setLoading(false); }
  }

  useEffect(() => { load(); }, []);

  async function remove(id) {
    if (!confirm('Delete this product?')) return;
    try {
      const res = await fetch(`http://localhost:5000/api/products/${id}`, {
        method: 'DELETE',
        headers: { Authorization: 'Bearer ' + getToken() }
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Delete failed');
      setMsg({ type: 'success', text: 'Deleted' });
      setProducts(products.filter(p => p._id !== id));
    } catch (err) {
      setMsg({ type: 'error', text: err.message });
    }
  }

  return (
    <div>
      <h3>Manage Products</h3>
      {msg && <div className={`alert ${msg.type}`}>{msg.text}</div>}
      <ProductForm onSaved={(p) => { setProducts([p, ...products]); setMsg({ type: 'success', text: 'Saved' }); }} editing={editing} setEditing={setEditing} />

      <div className="grid">
        {loading ? <p>Loading...</p> : products.map(p => (
          <div className="card" key={p._id}>
            {p.imagePath && <img src={`http://localhost:5000${p.imagePath}`} alt={p.name} />}
            <h4>{p.name}</h4>
            <p className="price">${p.price}</p>
            <div className="admin-actions">
              <button className="btn small" onClick={() => setEditing(p)}>Edit</button>
              <button className="btn small ghost" onClick={() => remove(p._id)}>Delete</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
